package server

import (
	"html"
	"net/http"
)

// MountAdminHome registers the operator-facing HTML page. The other
// /admin/* JSON endpoints are mounted by MountAdminWithDeps and
// MountLibraryRoutes; this file owns the shell that renders them.
//
// The same single-file template lives in three sibling plugins
// (bw-audio, bw-ebook, local-audiobooks) so an operator sees the
// same status strip, tab layout, and config form everywhere. Keeping
// the admin in one Go file means no JS toolchain per plugin, no
// node_modules drift, and a hotfix is one edit.
func MountAdminHome(mux *http.ServeMux) {
	mux.HandleFunc("GET /admin", handleAdminHome)
	mux.HandleFunc("GET /admin/", handleAdminHome)
	mux.HandleFunc("GET /", handleAdminHome)
}

func handleAdminHome(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	_, _ = w.Write([]byte(`<!doctype html>
<html lang="en" data-theme="` + adminTheme(r) + `">
<head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Local Ebooks</title><style>` + adminThemeCSS() + `</style></head>
<body>
<main class="shell">
<a class="back" href="/admin/plugins">&larr; Plugins</a>
<header><p class="eyebrow">Ebook backend</p><h1>Local Ebooks</h1><p>Local library scanning, metadata enrichment, covers, and file access for the Ebooks portal.</p></header>
<div id="status-strip" class="status-strip" aria-label="Plugin health"><div class="strip-cell"><span class="strip-dot"></span><strong>Loading…</strong></div></div>
<nav class="tabs" aria-label="Local Ebooks admin sections">
<button class="tab active" data-tab-target="libraries" type="button">Libraries</button>
<button class="tab" data-tab-target="scans" type="button">Scans</button>
<button class="tab" data-tab-target="metadata" type="button">Metadata</button>
<button class="tab" data-tab-target="diagnostics" type="button">Diagnostics</button>
</nav>
<section class="tab-panel active" id="libraries">
<article class="panel"><div class="panel-head"><div><h2>Library paths</h2><p class="muted">Paths are validated inside the plugin container. Use container-visible mounts such as <code>/mnt/ebooks</code> or <code>/srv/books</code>.</p></div><span id="path-count" class="badge">0 paths</span></div><form id="path-form" class="row"><input id="path" placeholder="/mnt/ebooks" aria-label="Container path"><button id="browse-path" type="button">Browse</button><input id="name" placeholder="Display name" aria-label="Display name"><select id="media-type" aria-label="Media type"><option value="book">book</option><option value="comics">comics</option><option value="manga">manga</option><option value="documents">documents</option></select><label class="check"><input id="enabled" type="checkbox" checked> Enabled</label><button type="submit">Add library</button></form><div id="path-browser" class="browser" hidden><div class="browser-head"><strong>Browse container paths</strong><button id="close-browser" type="button">Close</button></div><div class="browser-row"><input id="browser-path" value="/" aria-label="Browser path"><button id="open-browser-path" type="button">Open</button><button id="use-browser-path" type="button">Use this folder</button></div><div id="browser-status" class="muted">Choose a folder mounted inside the plugin container.</div><div id="browser-entries" class="browser-entries"></div></div><div id="paths" class="stack muted">Loading paths...</div></article>
</section>
<section class="tab-panel" id="scans">
<article class="panel"><div class="panel-head"><div><h2>Scan operations</h2><p class="muted">Run a global scan across every enabled library, or scan one library from its row on the Libraries tab.</p></div><span id="scan-state" class="badge">Loading</span></div><div id="scan-status" class="stack muted">Loading...</div><div class="actions"><button id="scan" type="button">Scan all libraries</button><button id="refresh-status" type="button">Refresh</button></div></article>
</section>
<section class="tab-panel" id="metadata">
<article class="panel"><div class="panel-head"><div><h2>Metadata settings</h2><p class="muted">Source selection, enrichment behavior, cache TTL, and external API keys.</p></div><button id="save-config" type="button">Save settings</button></div><form id="config-form" class="settings-grid"><label>Enabled sources<input id="metadata-sources" placeholder="googlebooks, isbndb, hardcover"></label><label>Scan source<input id="metadata-scan-source" placeholder="googlebooks"></label><label>Default region<input id="metadata-region" placeholder="us"></label><label>Cache TTL days<input id="metadata-cache-ttl" type="number" min="1"></label><label>Rate limit RPS<input id="metadata-rate-limit" type="number" min="1"></label><label class="check"><input id="scan-inline" type="checkbox"> Inline enrichment on scan</label><label>Google Books API key<input id="googlebooks-key" type="password" placeholder="Paste API key"></label><label>ISBNdb API key<input id="isbndb-key" type="password" placeholder="Paste API key"></label><label>Hardcover API key<input id="hardcover-key" type="password" placeholder="Paste API key"></label></form><div id="config-status" class="muted">Loading settings...</div></article>
<article class="panel"><div class="panel-head"><div><h2>Metadata enrichment</h2><p class="muted">Queue a backfill after large imports, provider changes, or when scanned books have weak metadata.</p></div></div><div id="metadata-status" class="muted">No backfill queued from this page yet.</div><div id="metadata-queue" class="diagnostic-grid"></div><div class="actions"><button id="backfill" type="button">Queue metadata backfill</button></div></article>
</section>
<section class="tab-panel" id="diagnostics">
<article class="panel"><div class="panel-head"><div><h2>Readiness diagnostics</h2><p class="muted">Use this before wiring the backend into the Ebooks portal.</p></div></div><div id="diagnostics-output" class="diagnostic-grid"></div></article>
</section>
<section class="panel"><h2>Operations checklist</h2><ul><li>Mount ebook folders into the plugin container before adding paths.</li><li>Add at least one enabled library, then run a scan.</li><li>Add this backend as a presentation library in the Ebooks portal.</li><li>Use metadata backfill after large imports or source changes.</li></ul></section>
</main>
<script>
const $=id=>document.getElementById(id);
const scanStatus=$("scan-status"), pathsEl=$("paths"), diagnosticsEl=$("diagnostics-output"), metadataStatus=$("metadata-status"), metadataQueueEl=$("metadata-queue"), configStatus=$("config-status"), scanButton=$("scan"), backfillButton=$("backfill"), saveConfigButton=$("save-config"), pathInput=$("path"), pathBrowser=$("path-browser"), browserPath=$("browser-path"), browserStatus=$("browser-status"), browserEntries=$("browser-entries");
const hostToken=new URLSearchParams(location.search).get("token")||"";
const adminBase=(location.pathname.match(/^(\/api\/v1\/plugins\/\d+)/)?.[1]||"")+"/admin";
function adminURL(path){return adminBase+path}
function adminHeaders(extra){return Object.assign(hostToken?{Authorization:"Bearer "+hostToken}:{},extra||{})}
async function json(url,init){const next=Object.assign({},init||{});next.headers=adminHeaders(next.headers);const r=await fetch(url,next);const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(d?.error?.message||d?.message||d?.error||("HTTP "+r.status));return d}
// el(tag, attrs?, ...children) — tiny safe-by-default DOM builder. Strings
// become textContent (no markup injection); nodes are appended as-is.
function el(tag,attrs,...children){const e=document.createElement(tag);if(attrs)for(const[k,v]of Object.entries(attrs)){if(k==="class")e.className=v;else if(k==="title"&&v)e.title=v;else if(k==="dataset")Object.assign(e.dataset,v);else if(k==="onClick")e.addEventListener("click",v);else if(k==="onChange")e.addEventListener("change",v);else if(k==="onBlur")e.addEventListener("blur",v);else if(v!==undefined&&v!==null&&v!==false)e.setAttribute(k,v===true?"":v)}for(const c of children){if(c==null||c===false)continue;e.appendChild(typeof c==="string"||typeof c==="number"?document.createTextNode(String(c)):c)}return e}
function setRows(parent,rows){parent.replaceChildren(...rows)}
function activateTab(id){document.querySelectorAll(".tab").forEach(b=>b.classList.toggle("active",b.dataset.tabTarget===id));document.querySelectorAll(".tab-panel").forEach(p=>p.classList.toggle("active",p.id===id))}
document.querySelectorAll(".tab").forEach(b=>b.addEventListener("click",()=>activateTab(b.dataset.tabTarget)))
function renderStrip(cells){const strip=$("status-strip");if(!strip)return;strip.replaceChildren(...cells.map(c=>el("div",{class:"strip-cell "+(c.ok?"ok":"bad"),title:c.detail||""},el("span",{class:"strip-dot"}),el("strong",null,c.label),el("span",null,c.ok?"OK":"Check"))))}
function diag(label,value){return el("div",{class:"diag"},el("span",null,label),el("strong",null,String(value)))}
function scanCard(e){const running=!e.finished_at;const cls="scan-card "+(e.error_text?"danger":running?"warning":"success");const lib=e.library_name||"all libraries";const children=[el("strong",null,"#"+e.id+" "+lib+" "+(running?"running":"finished")),el("span",null,e.started_at||""),el("small",null,"Added "+(e.books_added||0)+" · Changed "+(e.books_changed||0)+" · Deleted "+(e.books_deleted||0))];if(e.error_text)children.push(el("pre",null,e.error_text));return el("div",{class:cls},...children)}
const MEDIA_TYPES=["book","comics","manga","documents"];
let cachedPaths=[], cachedScans=[], cachedConfig={}, cachedDiag={}, keyState={googlebooks:false,isbndb:false,hardcover:false};
function libraryRow(p){const nameInput=el("input",{value:p.Name||"",placeholder:"Display name"});const mt=el("select");for(const m of MEDIA_TYPES){const opt=el("option",{value:m},m);if(p.MediaType===m)opt.selected=true;mt.appendChild(opt)}const en=el("input",{type:"checkbox"});en.checked=Boolean(p.Enabled);const ident=el("div",{class:"library-ident"},nameInput,el("small",null,p.Path));const enabledLabel=el("label",{class:"check"},en,document.createTextNode(" Enabled"));const last=el("small",{class:"muted last-scan"},p.LastScannedAt?("Last "+p.LastScannedAt):"Never scanned");const scanBtn=el("button",{type:"button",class:"secondary"},"Scan");const delBtn=el("button",{type:"button",class:"secondary danger"},"Remove");const actions=el("div",{class:"library-actions"},scanBtn,delBtn);scanBtn.addEventListener("click",async()=>{scanBtn.disabled=true;scanBtn.textContent="Starting...";try{await json(adminURL("/libraries/"+p.ID+"/scan"),{method:"POST"});scanBtn.textContent="Queued";await loadStatus()}catch(e){scanBtn.textContent="Error";console.error(e)}finally{setTimeout(()=>{scanBtn.disabled=false;scanBtn.textContent="Scan"},2000)}});delBtn.addEventListener("click",async()=>{if(!confirm('Remove "'+(p.Name||p.Path)+'"? Catalog rows are deleted; files on disk are untouched.'))return;try{await json(adminURL("/libraries/"+p.ID),{method:"DELETE"});await loadPaths()}catch(e){alert(e.message)}});async function patch(){try{await json(adminURL("/libraries/"+p.ID),{method:"PATCH",headers:{"Content-Type":"application/json"},body:JSON.stringify({name:nameInput.value,media_type:mt.value,enabled:en.checked})});await loadPaths()}catch(e){alert(e.message)}}nameInput.addEventListener("blur",()=>{if(nameInput.value!==(p.Name||""))patch()});mt.addEventListener("change",patch);en.addEventListener("change",patch);return el("div",{class:"path-row library-row"},ident,mt,enabledLabel,last,actions)}
async function loadStatus(){try{const d=await json(adminURL("/scans"));cachedScans=d.items||[];const active=cachedScans.find(e=>!e.finished_at);$("scan-state").textContent=active?"Scan running":"Idle";scanButton.disabled=Boolean(active);scanButton.textContent=active?"Scan running":"Scan all libraries";if(cachedScans.length)setRows(scanStatus,cachedScans.map(scanCard));else{scanStatus.replaceChildren();scanStatus.textContent="No scans recorded yet."}updateDiagnostics()}catch(e){scanStatus.replaceChildren();scanStatus.textContent=String(e);updateDiagnostics()}}
async function loadPaths(){try{const d=await json(adminURL("/libraries"));const items=d.items||[];cachedPaths=items;$("path-count").textContent=items.length+" path"+(items.length===1?"":"s");pathsEl.replaceChildren();if(!items.length){pathsEl.textContent="No library paths configured.";updateDiagnostics();return}for(const p of items)pathsEl.appendChild(libraryRow(p));updateDiagnostics()}catch(e){pathsEl.replaceChildren();pathsEl.textContent=String(e);updateDiagnostics()}}
function writeConfigForm(c){cachedConfig=c||{};$("metadata-sources").value=(c.metadata_sources_enabled||[]).join(", ");$("metadata-scan-source").value=c.metadata_scan_source||"";$("metadata-region").value=c.metadata_default_region||"us";$("metadata-cache-ttl").value=c.metadata_cache_ttl_days||30;$("metadata-rate-limit").value=c.metadata_rate_limit_rps||5;$("scan-inline").checked=Boolean(c.scan_inline_enrich);/* Never echo secrets back into the DOM — type="password" still ships the value as input.value. Show "configured" via placeholder and use empty submit to mean "leave it alone". */ keyState.googlebooks=Boolean(c.googlebooks_api_key);keyState.isbndb=Boolean(c.isbndb_api_key);keyState.hardcover=Boolean(c.hardcover_api_key);for(const [id,k] of[["googlebooks-key","googlebooks"],["isbndb-key","isbndb"],["hardcover-key","hardcover"]]){const inp=$(id);inp.value="";inp.placeholder=keyState[k]?"✓ configured (leave blank to keep)":"Paste API key"}}
function readConfigForm(){const sources=$("metadata-sources").value.split(",").map(x=>x.trim()).filter(Boolean);const body={metadata_sources_enabled:sources,metadata_scan_source:$("metadata-scan-source").value.trim(),metadata_default_region:$("metadata-region").value.trim(),metadata_cache_ttl_days:Number($("metadata-cache-ttl").value)||30,metadata_rate_limit_rps:Number($("metadata-rate-limit").value)||5,scan_inline_enrich:$("scan-inline").checked};const gb=$("googlebooks-key").value.trim();const idb=$("isbndb-key").value.trim();const hc=$("hardcover-key").value.trim();body.googlebooks_api_key=gb||cachedConfig.googlebooks_api_key||"";body.isbndb_api_key=idb||cachedConfig.isbndb_api_key||"";body.hardcover_api_key=hc||cachedConfig.hardcover_api_key||"";return body}
async function loadConfig(){try{const c=await json(adminURL("/config"));writeConfigForm(c);configStatus.textContent="Settings loaded";updateDiagnostics()}catch(e){configStatus.textContent=String(e)}}
async function loadQueue(){try{const q=await json(adminURL("/metadata/queue"));const entries=Object.entries(q||{});if(entries.length)setRows(metadataQueueEl,entries.map(([k,v])=>diag(k,v)));else setRows(metadataQueueEl,[el("div",{class:"diag muted"},"Queue is empty.")])}catch(e){setRows(metadataQueueEl,[el("div",{class:"diag muted"},String(e))])}}
async function loadDiagnostics(){try{cachedDiag=await json(adminURL("/diagnostics"))}catch(e){cachedDiag={error:String(e)}}finally{updateDiagnostics()}}
function updateDiagnostics(){const d=cachedDiag||{};const dbOK=Boolean(d.database?.ok);const paths=cachedPaths||[];const last=(cachedScans||[])[0];const active=(cachedScans||[]).find(e=>!e.finished_at);const catalog=d.catalog||{};const queue=d.metadata||{};const rows=[["Plugin id",d.plugin_id||"silo.local-ebooks"],["Role",d.role||"library_source_and_metadata_provider"],["Database",d.database?.message||"unknown"],["Libraries",paths.length+" configured"],["Books in catalog",catalog.books??"unknown"],["Files in catalog",catalog.files??"unknown"],["Metadata queue total",queue.total??"unknown"],["Pending enrichment",queue.pending??queue.queued??"unknown"],["Active scan",active?("#"+active.id):"None"],["Last scan",last?((last.error_text?"Failed":"Completed")+" #"+last.id):"Never"]];setRows(diagnosticsEl,rows.map(([k,v])=>diag(k,v)));const sourcesCount=(cachedConfig.metadata_sources_enabled||[]).length;renderStrip([{label:'DB',ok:dbOK,detail:d.database?.message},{label:'Libraries',ok:paths.length>0,detail:paths.length+' configured'},{label:'Sources',ok:sourcesCount>0,detail:sourcesCount+' enabled'},{label:'Last scan',ok:!last||!last.error_text,detail:last?(last.error_text?'failed: '+last.error_text:'completed'):'never run'},{label:'Active scan',ok:!active,detail:active?'scan #'+active.id+' running':'idle'}])}
async function browsePath(path){browserStatus.textContent="Loading...";browserEntries.replaceChildren();try{const d=await json(adminURL("/filesystem/browse?"+new URLSearchParams({path:path||"/"}).toString()));browserPath.value=d.path;browserStatus.textContent=d.entries?.length?d.entries.length+" folder"+(d.entries.length===1?"":"s"):"No child folders";const rows=[];if(d.parent&&d.parent!==d.path){const b=el("button",{type:"button"},el("span",null,".. "),el("small",null,d.parent));b.addEventListener("click",()=>browsePath(d.parent));rows.push(b)}for(const e of d.entries||[]){const b=el("button",{type:"button"},el("strong",null,e.name),el("small",null,e.path));b.addEventListener("click",()=>browsePath(e.path));rows.push(b)}browserEntries.replaceChildren(...rows)}catch(e){browserStatus.textContent=String(e)}}
$("browse-path").addEventListener("click",()=>{pathBrowser.hidden=false;browsePath(pathInput.value||"/")})
$("close-browser").addEventListener("click",()=>{pathBrowser.hidden=true})
$("open-browser-path").addEventListener("click",()=>browsePath(browserPath.value||"/"))
$("use-browser-path").addEventListener("click",()=>{pathInput.value=browserPath.value;pathBrowser.hidden=true;pathInput.focus()})
scanButton.addEventListener("click",async()=>{scanButton.disabled=true;scanButton.textContent="Starting...";try{const d=await json(adminURL("/scan"),{method:"POST"});scanStatus.replaceChildren(el("div",{class:"scan-card warning"},el("strong",null,"Scan queued #"+d.scan_event_id),el("span",null,"Refreshing status...")));await loadStatus()}catch(e){scanStatus.replaceChildren();scanStatus.textContent=String(e);scanButton.disabled=false;scanButton.textContent="Scan all libraries"}})
$("refresh-status").addEventListener("click",loadStatus)
backfillButton.addEventListener("click",async()=>{backfillButton.disabled=true;metadataStatus.textContent="Queueing metadata backfill...";try{const d=await json(adminURL("/metadata/backfill"),{method:"POST"});metadataStatus.replaceChildren();metadataStatus.appendChild(el("div",{class:"scan-card success"},el("strong",null,"Backfill queued"),el("span",null,(d.queued||0)+" jobs queued")));await loadQueue();await loadDiagnostics()}catch(e){metadataStatus.textContent=String(e)}finally{backfillButton.disabled=false}})
saveConfigButton.addEventListener("click",async()=>{saveConfigButton.disabled=true;configStatus.textContent="Saving settings...";try{const c=await json(adminURL("/config"),{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify(readConfigForm())});writeConfigForm(c);configStatus.textContent="Settings saved.";await loadDiagnostics()}catch(e){configStatus.textContent=String(e)}finally{saveConfigButton.disabled=false}})
$("path-form").addEventListener("submit",async e=>{e.preventDefault();try{await json(adminURL("/libraries"),{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({path:$("path").value,name:$("name").value,media_type:$("media-type").value,enabled:$("enabled").checked})});e.target.reset();$("enabled").checked=true;await loadPaths()}catch(err){alert(err.message)}})
loadStatus();loadPaths();loadConfig();loadQueue();loadDiagnostics();
</script>
</body></html>`))
}

func adminTheme(r *http.Request) string {
	theme := r.Header.Get("X-Silo-Theme")
	if theme == "" {
		theme = r.URL.Query().Get("theme")
	}
	if theme == "" {
		theme = r.Header.Get("X-Silo-User-Theme")
	}
	if theme == "" {
		theme = "default"
	}
	return html.EscapeString(theme)
}

func adminThemeCSS() string {
	return `:root{--bg:#141417;--fg:#e8e8ec;--muted:#a1a1aa;--link:#93c5fd;--panel:#1c1c20;--border:#28282e;--input:#101014;--ok:#22c55e;--warn:#f59e0b;--bad:#ef4444}[data-theme="cinema-light"]{--bg:#f7f3ed;--fg:#201c18;--muted:#756b60;--link:#9a3412;--panel:#fffaf3;--border:#ded1c0;--input:#fff}[data-theme="cobalt-studio"]{--bg:#101623;--fg:#eef4ff;--muted:#afc2e2;--link:#60a5fa;--panel:#172033;--border:#2d3f61;--input:#0d1422}[data-theme="oxblood-noir"]{--bg:#170b10;--fg:#fff1f4;--muted:#f0a6b7;--link:#fb7185;--panel:#241018;--border:#4a2230;--input:#12070b}[data-theme="evergreen-studio"]{--bg:#0d1712;--fg:#ecfdf3;--muted:#9bd6b4;--link:#6ee7b7;--panel:#14241b;--border:#2b4b39;--input:#08110d}*{box-sizing:border-box}body{font-family:system-ui,sans-serif;margin:0;line-height:1.5;background:var(--bg);color:var(--fg)}.shell{max-width:1120px;margin:0 auto;padding:28px}.back{display:inline-flex;margin-bottom:12px;color:var(--link);text-decoration:none}.eyebrow{color:var(--muted);text-transform:uppercase;font-size:12px;letter-spacing:.08em}h1{margin:.2rem 0}h2{font-size:16px;margin:0}.tabs{display:flex;gap:8px;flex-wrap:wrap;margin:18px 0}.tab{background:transparent;color:var(--fg);border:1px solid var(--border)}.tab.active{background:var(--link);color:#08111f}.tab-panel{display:none}.tab-panel.active{display:block}.panel{border:1px solid var(--border);background:var(--panel);border-radius:8px;padding:16px;margin-top:16px}.panel-head{display:flex;justify-content:space-between;gap:16px;align-items:flex-start}.row{display:grid;grid-template-columns:minmax(0,1fr) auto minmax(0,180px) auto auto auto;gap:8px;align-items:center}.settings-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px;margin:12px 0}.settings-grid label{display:grid;gap:5px;color:var(--muted);font-size:13px}.settings-grid .check{display:flex;align-items:center;color:var(--fg);padding-top:20px}.actions{display:flex;gap:8px;margin-top:12px;flex-wrap:wrap}.stack{display:grid;gap:8px}.stack>*+*{margin-top:0}input,select{min-width:0;background:var(--input);color:var(--fg);border:1px solid var(--border);border-radius:6px;padding:9px}input[type="checkbox"]{width:auto}button{background:var(--link);border:0;border-radius:6px;padding:9px 12px;color:#08111f;font-weight:700;cursor:pointer}button.secondary{background:transparent;border:1px solid var(--border);color:var(--fg);font-weight:600}button.secondary.danger{color:var(--bad);border-color:color-mix(in srgb,var(--bad) 55%,var(--border))}button:disabled{opacity:.6;cursor:not-allowed}.muted{color:var(--muted)}.badge{border:1px solid var(--border);border-radius:999px;padding:4px 9px;color:var(--muted);white-space:nowrap}.check{display:flex!important;align-items:center;gap:6px}.output,.scan-card{overflow:auto;background:var(--input);border:1px solid var(--border);border-radius:6px;padding:10px;color:var(--fg)}.scan-card{display:grid;gap:3px}.scan-card small,.scan-card span{color:var(--muted)}.scan-card.success{border-color:color-mix(in srgb,var(--ok) 45%,var(--border))}.scan-card.warning{border-color:color-mix(in srgb,var(--warn) 55%,var(--border))}.scan-card.danger{border-color:color-mix(in srgb,var(--bad) 55%,var(--border))}.path-row{display:flex;align-items:center;justify-content:space-between;gap:10px;border:1px solid var(--border);border-radius:6px;padding:10px;background:var(--input)}.path-row small{color:var(--muted)}.library-row{display:grid;grid-template-columns:minmax(0,1fr) 130px auto auto auto;gap:10px;align-items:center}.library-ident{display:grid;gap:4px;min-width:0}.library-ident input{padding:6px 8px}.library-ident small{overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.library-actions{display:flex;gap:6px}.last-scan{font-size:12px;color:var(--muted)}.browser{margin:12px 0;border:1px solid var(--border);border-radius:8px;background:var(--input);padding:12px}.browser-head,.browser-row{display:flex;align-items:center;justify-content:space-between;gap:8px;margin-bottom:8px}.browser-row input{flex:1}.browser-entries{display:grid;max-height:280px;overflow:auto;border:1px solid var(--border);border-radius:6px}.browser-entries button{display:grid;grid-template-columns:180px minmax(0,1fr);gap:8px;border-radius:0;border-bottom:1px solid var(--border);background:transparent;color:var(--fg);text-align:left}.browser-entries small{color:var(--muted);overflow:hidden;text-overflow:ellipsis}.diagnostic-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:10px}.diag{display:grid;gap:4px;border:1px solid var(--border);border-radius:6px;background:var(--input);padding:12px}.diag span{color:var(--muted);font-size:12px}.diag strong{font-size:18px}code{color:var(--link)}.status-strip{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:8px;margin-top:14px}.strip-cell{display:flex;align-items:center;gap:8px;border:1px solid var(--border);background:var(--panel);border-radius:6px;padding:8px 10px;font-size:12px}.strip-dot{flex:0 0 8px;width:8px;height:8px;border-radius:999px;background:var(--muted)}.strip-cell.ok .strip-dot{background:var(--ok)}.strip-cell.bad .strip-dot{background:var(--bad)}.strip-cell strong{font-weight:600;color:var(--fg)}.strip-cell span{color:var(--muted);margin-left:auto;font-size:11px}@media(max-width:760px){.row,.panel-head,.browser-row,.library-row{grid-template-columns:1fr;display:grid}.panel-head{gap:8px}.browser-entries button{grid-template-columns:1fr}}`
}
